class Solution {
public:
    int findUnsortedSubarray(vector<int>& nums) {
        int n = nums.size(), lo=0, hi=n-1;
        while (lo<n-1 && nums[lo]<=nums[lo+1]) lo++;
        if (lo==n-1) return 0;
        while (hi>0 && nums[hi]>=nums[hi-1]) hi--;
        int submax=*max_element(nums.begin()+lo, nums.begin()+hi+1);
        int submin=*min_element(nums.begin()+lo, nums.begin()+hi+1);
        while (lo>0 && nums[lo-1]>submin) lo--;
        while (hi<n-1 && nums[hi+1]<submax) hi++;
        return hi-lo+1;
    }
};
